import{_ as o,o as t,c as a,a4 as s}from"./chunks/framework.m9mi3vzv.js";const h=JSON.parse('{"title":"ADR-007: Monorepo (yarn + Turborepo), vitest, lockstep versions","description":"","frontmatter":{},"headers":[],"relativePath":"reference/decisions/ADR-007-monorepo-restructure.md","filePath":"reference/decisions/ADR-007-monorepo-restructure.md"}'),r={name:"reference/decisions/ADR-007-monorepo-restructure.md"};function n(i,e,c,d,l,p){return t(),a("div",null,[...e[0]||(e[0]=[s('<h1 id="adr-007-monorepo-yarn-turborepo-vitest-lockstep-versions" tabindex="-1">ADR-007: Monorepo (yarn + Turborepo), vitest, lockstep versions <a class="header-anchor" href="#adr-007-monorepo-yarn-turborepo-vitest-lockstep-versions" aria-label="Permalink to &quot;ADR-007: Monorepo (yarn + Turborepo), vitest, lockstep versions&quot;">​</a></h1><blockquote><p><strong>Date</strong>: 2026-06-28 <strong>Status</strong>: Accepted <strong>Source</strong>: Plan: monorepo-restructure</p></blockquote><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>The SDK began as a single package, <code>@blendsdk/tui</code>. As the project grows beyond the foundation engine (widgets, layout, an app runloop, and the dev examples/probe harness), one package conflates the published library with dev-only tooling and leaves no room for additional published packages. We also wanted a faster, cached build/test pipeline and a modern test runner.</p><h2 id="options-considered" tabindex="-1">Options Considered <a class="header-anchor" href="#options-considered" aria-label="Permalink to &quot;Options Considered&quot;">​</a></h2><h3 id="option-a-stay-single-package" tabindex="-1">Option A: Stay single-package <a class="header-anchor" href="#option-a-stay-single-package" aria-label="Permalink to &quot;Option A: Stay single-package&quot;">​</a></h3><ul><li><strong>Pros</strong>: Simplest; no workspace tooling.</li><li><strong>Cons</strong>: No home for future packages; dev examples ship-or-pollute the published surface; no shared task caching.</li></ul><h3 id="option-b-yarn-1-x-workspaces-turborepo-vitest-lockstep-versions" tabindex="-1">Option B: yarn 1.x workspaces + Turborepo, vitest, lockstep versions <a class="header-anchor" href="#option-b-yarn-1-x-workspaces-turborepo-vitest-lockstep-versions" aria-label="Permalink to &quot;Option B: yarn 1.x workspaces + Turborepo, vitest, lockstep versions&quot;">​</a></h3><ul><li><strong>Pros</strong>: Clean package boundaries (<code>@blendsdk/tui-core</code> published, <code>@blendsdk/tui-examples</code> private); cached cross-package <code>build</code>/<code>typecheck</code>/<code>test</code>; vitest&#39;s fast watch + projects (unit vs e2e); one source-of-truth version across public packages.</li><li><strong>Cons</strong>: Workspace/tooling overhead; a one-time test-runner migration (<code>node:test</code> → vitest); the Node floor must rise to ≥ 20 (latest vitest dropped 18).</li></ul><h2 id="decision" tabindex="-1">Decision <a class="header-anchor" href="#decision" aria-label="Permalink to &quot;Decision&quot;">​</a></h2><p><strong>Chosen option</strong>: Option B — a yarn 1.x + Turborepo monorepo. The engine becomes <code>@blendsdk/tui-core</code> under <code>packages/tui-core/</code>; examples + the probe harness become the private <code>@blendsdk/tui-examples</code>. Future packages are <code>@blendsdk/tui-&lt;name&gt;</code>. Tests run on vitest (<code>unit</code> + <code>e2e</code> projects). A <code>sync-versions</code> script keeps all public packages on the root <code>package.json#version</code> in lockstep.</p><h2 id="rationale" tabindex="-1">Rationale <a class="header-anchor" href="#rationale" aria-label="Permalink to &quot;Rationale&quot;">​</a></h2><p>The split cleanly separates the published contract (tui-core, still ESM-only / zero-runtime-dep — <a href="/jsvision/reference/decisions/ADR-001-esm-zero-dependency.html">ADR-001</a>) from dev-only example code, and opens room for the widget/app packages the foundation exists to support. Turborepo caches and orders cross-package tasks (<code>^build</code> so consumers typecheck against built <code>.d.ts</code>). vitest replaces the bespoke Node-version-dependent test runner and resolves the NodeNext <code>.js</code>→<code>.ts</code> specifiers natively. The <code>node:assert</code> → <code>expect()</code> migration was a semantics-preserving syntax change — no spec-test expectation moved. Node 18 was already EOL, so raising the floor to ≥ 20 to adopt the latest vitest cost nothing real.</p><h2 id="consequences" tabindex="-1">Consequences <a class="header-anchor" href="#consequences" aria-label="Permalink to &quot;Consequences&quot;">​</a></h2><h3 id="positive" tabindex="-1">Positive <a class="header-anchor" href="#positive" aria-label="Permalink to &quot;Positive&quot;">​</a></h3><ul><li>Clear package boundaries; a place for <code>@blendsdk/tui-&lt;name&gt;</code> packages.</li><li>Cached, ordered builds/tests via Turborepo; fast vitest runs.</li><li>Lockstep versions prevent public-package version drift.</li></ul><h3 id="negative" tabindex="-1">Negative <a class="header-anchor" href="#negative" aria-label="Permalink to &quot;Negative&quot;">​</a></h3><ul><li>More tooling (yarn workspaces, turbo, two vitest configs) to maintain.</li><li>Governance tests (gate/docs/api-stability) currently reach the monorepo root from <code>tui-core</code> via <code>../../..</code> (tracked as a cleanup, DEF-4).</li></ul><h3 id="risks" tabindex="-1">Risks <a class="header-anchor" href="#risks" aria-label="Permalink to &quot;Risks&quot;">​</a></h3><ul><li>Publishing is not yet wired (provenance deferred — RD-10 DEF-1 / DEF-2); the packaging contract is still verified by <code>packaging.spec</code> + the install e2e.</li></ul>',20)])])}const g=o(r,[["render",n]]);export{h as __pageData,g as default};
